void solve(int CASE)
{
	int n; cin >> n;
	string s; cin >> s;
	s = "  " + s;
	var _0 = vector<int>();
	var _1 = vector<int>();
	fa(i, 2, n - 1) {
		if (s[i] == '1')_1.pb(i);
		else _0.pb(i);
	}
	if (_0.size() == 0 or
		_0.size() == 1 and s[n - 1] != '0') {
		cout << -1 << endl;
		return;
	}

	var ans = vector<pii>();

	// 非割点组成环，挂载在 1 上
	int last = 1;
	for (int x : _0) {
		ans.pb({ last, x });
		last = x;
	}
	if (_0.size() != 1)ans.pb({ last, 1 });

	// 割点组成链，挂载在 1 上
	last = 1;
	for (int x : _1) {
		ans.pb({ last, x });
		last = x;
	}
	ans.pb({ last,n });

	cout << ans.size() << endl;
	for (const var& [x, y] : ans)cout << x << ' ' << y << endl;
	return;
}
